class Card{constructor(data,game){this.word=data.word,this.type=data.type,this.game=game,this.flipped=!1,this.element=document.createElement("div"),this.element.classList.add("card");const content=document.createElement("div");content.classList.add("card-content");const wordEl=document.createElement("div");wordEl.classList.add("word"),wordEl.innerText=this.word;const typeEl=document.createElement("div");typeEl.classList.add("type"),typeEl.innerText=this.type,content.appendChild(wordEl),content.appendChild(typeEl),this.element.appendChild(content),this.element.addEventListener("click",(()=>this.handleClick()))}handleClick(){this.flipped||this.game.lockBoard||(this.flip(),this.game.firstCard?(this.game.secondCard=this,this.game.lockBoard=!0,this.game.checkMatch()):this.game.firstCard=this)}flip(){this.flipped=!0,this.element.classList.add("flipped")}flipBack(){this.flipped=!1,this.element.classList.remove("flipped")}setMatched(){this.element.classList.add("matched")}}